namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = new();
    public List<string> Steps { get; set; } = new();
    public List<int> Ratings { get; set; } = new();

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1,
            Title = "Classic Margherita Pizza",
            Category = "Italian",
            Ingredients = new() { "Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt" },
            Steps = new() { "Preheat oven to 475°F (245°C).", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly over dough.", "Tear mozzarella and distribute over sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil." },
            Ratings = new() { 5, 4, 5, 4, 5 }
        },
        new Recipe
        {
            Id = 2,
            Title = "Spaghetti Carbonara",
            Category = "Italian",
            Ingredients = new() { "Spaghetti", "Guanciale or pancetta", "Eggs", "Pecorino Romano", "Black pepper" },
            Steps = new() { "Cook spaghetti in salted boiling water until al dente.", "Crisp guanciale in a pan over medium heat.", "Whisk eggs with grated pecorino and pepper.", "Toss hot pasta with guanciale and rendered fat.", "Remove from heat and stir in egg mixture quickly.", "Serve immediately with extra pecorino and pepper." },
            Ratings = new() { 5, 5, 4 }
        },
        new Recipe
        {
            Id = 3,
            Title = "Chicken Tikka Masala",
            Category = "Indian",
            Ingredients = new() { "Chicken thighs", "Yogurt", "Garam masala", "Tomato puree", "Heavy cream", "Onion", "Garlic", "Ginger" },
            Steps = new() { "Marinate chicken in yogurt and spices for 2 hours.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger until soft.", "Add tomato puree and spices, simmer 15 minutes.", "Stir in cream and add cooked chicken.", "Simmer 10 more minutes and serve with rice." },
            Ratings = new() { 5, 4, 5, 5 }
        },
        new Recipe
        {
            Id = 4,
            Title = "Vegetable Pad Thai",
            Category = "Thai",
            Ingredients = new() { "Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Tamarind paste", "Fish sauce", "Lime", "Scallions" },
            Steps = new() { "Soak rice noodles in warm water for 30 minutes.", "Press and cube tofu, then pan-fry until golden.", "Mix tamarind paste, fish sauce, sugar, and lime juice.", "Stir-fry noodles with sauce on high heat.", "Add tofu and bean sprouts, toss together.", "Garnish with crushed peanuts and scallions." },
            Ratings = new() { 4, 4, 5 }
        },
        new Recipe
        {
            Id = 5,
            Title = "Beef Tacos",
            Category = "Mexican",
            Ingredients = new() { "Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Cumin", "Chili powder" },
            Steps = new() { "Brown ground beef in a skillet over medium-high heat.", "Season with cumin, chili powder, salt, and pepper.", "Warm taco shells in the oven for 3 minutes.", "Shred lettuce, dice tomato, and grate cheese.", "Fill shells with seasoned beef.", "Top with lettuce, tomato, cheese, and sour cream." },
            Ratings = new() { 4, 5, 4, 4 }
        },
        new Recipe
        {
            Id = 6,
            Title = "Green Curry",
            Category = "Thai",
            Ingredients = new() { "Coconut milk", "Green curry paste", "Chicken breast", "Bamboo shoots", "Thai basil", "Fish sauce", "Sugar", "Jasmine rice" },
            Steps = new() { "Cook curry paste in coconut cream until fragrant.", "Add sliced chicken and cook through.", "Pour in remaining coconut milk and bring to simmer.", "Add bamboo shoots and season with fish sauce and sugar.", "Stir in Thai basil leaves.", "Serve over steamed jasmine rice." },
            Ratings = new() { 5, 5, 4, 5 }
        }
    };

    private int _nextId = 7;

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int rating)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && rating >= 1 && rating <= 5)
        {
            recipe.Ratings.Add(rating);
        }
    }

    public Recipe AddRecipe(string title, string category, List<string> ingredients, List<string> steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

