arguments.new_str:
@page "/"

<PageTitle>Recipe Community - Home</PageTitle>

<div class="container">
    <div class="text-center my-5">
        <h1>🍳 Recipe Community</h1>
        <p class="lead">Discover and share delicious recipes from around the world</p>
    </div>

    <h2 class="mb-4">Browse by Category</h2>
    <div class="row">
        @foreach (var category in Categories)
        {
            <div class="col-md-3 mb-4">
                <a href="/recipes/@category" class="text-decoration-none">
                    <div class="card h-100 text-center shadow-sm">
                        <div class="card-body">
                            <h3 class="card-title">@GetCategoryEmoji(category)</h3>
                            <h5>@category</h5>
                            <p class="text-muted">@GetRecipeCount(category) recipes</p>
                        </div>
                    </div>
                </a>
            </div>
        }
    </div>
</div>

@code {
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> Categories = Array.Empty<string>();

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private int GetRecipeCount(string category) => RecipeService.GetByCategory(category).Count;

    private string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Thai" => "🍜",
        "Mexican" => "🌮",
        _ => "🍽️"
    };
}

arguments.file_text:
@page "/recipes/{Category}"

<PageTitle>@Category Recipes - Recipe Community</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@Category</li>
        </ol>
    </nav>

    <h1>@Category Recipes</h1>

    @if (Recipes.Count == 0)
    {
        <p class="text-muted">No recipes found in this category.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in Recipes)
            {
                <div class="col-md-6 mb-4">
                    <div class="card shadow-sm">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="text-warning mb-1">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    <span>@(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")</span>
                                }
                                <small class="text-muted ms-1">(@recipe.Ratings.Count ratings)</small>
                            </p>
                            <a href="/recipe/@recipe.Id" class="btn btn-outline-primary btn-sm mt-2">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string Category { get; set; } = string.Empty;
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<RecipeCommunity.Models.Recipe> Recipes = Array.Empty<RecipeCommunity.Models.Recipe>();

    protected override void OnInitialized()
    {
        Recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (Recipe is not null)
            {
                <li class="breadcrumb-item"><a href="/recipes/@Recipe.Category">@Recipe.Category</a></li>
                <li class="breadcrumb-item active">@Recipe.Title</li>
            }
        </ol>
    </nav>

    @if (Recipe is null)
    {
        <p class="text-danger">Recipe not found.</p>
    }
    else
    {
        <h1>@Recipe.Title</h1>
        <span class="badge bg-secondary mb-3">@Recipe.Category</span>

        <div class="my-3">
            <StarRating RecipeId="@Recipe.Id" />
        </div>

        <div class="row mt-4">
            <div class="col-md-4">
                <div class="card">
                    <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                    <ul class="list-group list-group-flush">
                        @foreach (var ingredient in Recipe.Ingredients)
                        {
                            <li class="list-group-item">@ingredient</li>
                        }
                    </ul>
                </div>
            </div>
            <div class="col-md-8">
                <div class="card">
                    <div class="card-header"><h5 class="mb-0">Steps</h5></div>
                    <div class="card-body">
                        <ol>
                            @foreach (var step in Recipe.Steps)
                            {
                                <li class="mb-2">@step</li>
                            }
                        </ol>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeCommunity.Models.Recipe? Recipe;

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

<div class="d-inline-block">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="fs-4" style="cursor: pointer; color: @(star <= DisplayRating ? "#ffc107" : "#e0e0e0");"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => HoverRating = star"
              @onmouseout="() => HoverRating = 0">★</span>
    }
    @if (Submitted)
    {
        <span class="text-success ms-2">✓ Thanks for rating!</span>
    }
    <br />
    <small class="text-muted">
        Average: @AverageRating.ToString("0.0") / 5 (@RatingCount ratings)
    </small>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private int HoverRating;
    private int SelectedRating;
    private bool Submitted;
    private double AverageRating;
    private int RatingCount;

    private int DisplayRating => HoverRating > 0 ? HoverRating : SelectedRating;

    protected override void OnInitialized()
    {
        RefreshStats();
    }

    private void SubmitRating(int rating)
    {
        SelectedRating = rating;
        RecipeService.AddRating(RecipeId, rating);
        Submitted = true;
        RefreshStats();
    }

    private void RefreshStats()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.Ratings.Count;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container">
    <h1>Submit a Recipe</h1>
    <p class="text-muted">Share your favorite recipe with the community!</p>

    @if (SubmittedRecipe is not null)
    {
        <div class="alert alert-success">
            <strong>Recipe submitted!</strong> Your recipe "<em>@SubmittedRecipe.Title</em>" has been added.
            <a href="/recipe/@SubmittedRecipe.Id">View it here</a>.
        </div>
    }

    <div class="card shadow-sm">
        <div class="card-body">
            <EditForm Model="FormModel" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label class="form-label">Recipe Title</label>
                    <InputText @bind-Value="FormModel.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Category</label>
