@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (Recipe is not null)
            {
                <li class="breadcrumb-item"><a href="/recipes/@Recipe.Category">@Recipe.Category</a></li>
                <li class="breadcrumb-item active">@Recipe.Title</li>
            }
        </ol>
    </nav>

    @if (Recipe is null)
    {
        <p class="text-danger">Recipe not found.</p>
    }
    else
    {
        <h1>@Recipe.Title</h1>
        <span class="badge bg-secondary mb-3">@Recipe.Category</span>

        <div class="my-3">
            <StarRating RecipeId="@Recipe.Id" />
        </div>

        <div class="row mt-4">
            <div class="col-md-4">
                <div class="card">
                    <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                    <ul class="list-group list-group-flush">
                        @foreach (var ingredient in Recipe.Ingredients)
                        {
                            <li class="list-group-item">@ingredient</li>
                        }
                    </ul>
                </div>
            </div>
            <div class="col-md-8">
                <div class="card">
                    <div class="card-header"><h5 class="mb-0">Steps</h5></div>
                    <div class="card-body">
                        <ol>
                            @foreach (var step in Recipe.Steps)
                            {
                                <li class="mb-2">@step</li>
                            }
                        </ol>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeCommunity.Models.Recipe? Recipe;

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

<div class="d-inline-block">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="fs-4" style="cursor: pointer; color: @(star <= DisplayRating ? "#ffc107" : "#e0e0e0");"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => HoverRating = star"
              @onmouseout="() => HoverRating = 0">★</span>
    }
    @if (Submitted)
    {
        <span class="text-success ms-2">✓ Thanks for rating!</span>
    }
    <br />
    <small class="text-muted">
        Average: @AverageRating.ToString("0.0") / 5 (@RatingCount ratings)
    </small>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private int HoverRating;
    private int SelectedRating;
    private bool Submitted;
    private double AverageRating;
    private int RatingCount;

    private int DisplayRating => HoverRating > 0 ? HoverRating : SelectedRating;

    protected override void OnInitialized()
    {
        RefreshStats();
    }

    private void SubmitRating(int rating)
    {
        SelectedRating = rating;
        RecipeService.AddRating(RecipeId, rating);
        Submitted = true;
        RefreshStats();
    }

    private void RefreshStats()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.Ratings.Count;
        }
    }
}

