toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container">
    <h1>Submit a Recipe</h1>
    <p class="text-muted">Share your favorite recipe with the community!</p>

    @if (SubmittedRecipe is not null)
    {
        <div class="alert alert-success">
            <strong>Recipe submitted!</strong> Your recipe "<em>@SubmittedRecipe.Title</em>" has been added.
            <a href="/recipe/@SubmittedRecipe.Id">View it here</a>.
        </div>
    }

    <div class="card shadow-sm">
        <div class="card-body">
            <EditForm Model="FormModel" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label class="form-label">Recipe Title</label>
                    <InputText @bind-Value="FormModel.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Category</label>
                    <InputSelect @bind-Value="FormModel.Category" class="form-select">
                        <option value="">-- Select a category --</option>
                        <option value="Italian">Italian</option>
                        <option value="Indian">Indian</option>
                        <option value="Thai">Thai</option>
                        <option value="Mexican">Mexican</option>
                        <option value="American">American</option>
                        <option value="French">French</option>
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label class="form-label">Ingredients (one per line)</label>
                    <InputTextArea @bind-Value="FormModel.IngredientsText" class="form-control" rows="5"
                                   placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Steps (one per line)</label>
                    <InputTextArea @bind-Value="FormModel.StepsText" class="form-control" rows="5"
                                   placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Combine wet and dry" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Recipe</button>
            </EditForm>
        </div>
    </div>
</div>

@code {
    [Inject] private RecipeCommunity.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel FormModel { get; set; } = new();
    private RecipeCommunity.Models.Recipe? SubmittedRecipe;

    private void HandleSubmit()
    {
        var ingredients = FormModel.IngredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        var steps = FormModel.StepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        SubmittedRecipe = RecipeService.AddRecipe(FormModel.Title, FormModel.Category, ingredients, steps);
        FormModel = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "At least one ingredient is required")]
        public string IngredientsText { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "At least one step is required")]
        public string StepsText { get; set; } = string.Empty;
    }
}

